import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function ClientManagement(){

const [showForm,setShowForm] = useState(false);
const [clients,setClients] = useState([]);
const [projects,setProjects] = useState([]);
const [search,setSearch] = useState("");
const [editId,setEditId] = useState(null);

const [formData,setFormData] = useState({
name:"",
phone:"",
address:"",
project:"",
floor:"",
room:"",
amount_paid:""
});


// ================= LOAD CLIENTS =================
const fetchClients = async ()=>{

try{

const res = await fetch("http://localhost:5000/api/clients");
const data = await res.json();

setClients(data);

}catch(err){
console.log(err);
}

};


// ================= LOAD PROJECTS =================
const fetchProjects = async ()=>{

try{

const res = await fetch("http://localhost:5000/api/projects");
const data = await res.json();

setProjects(data);

}catch(err){
console.log(err);
}

};


// ================= GENERATE ROOMS =================
const generateRooms = (floor)=>{

if(!floor) return [];

let rooms=[];

for(let i=1;i<=10;i++){

rooms.push(`${floor}${i.toString().padStart(2,"0")}`);

}

return rooms;

};


useEffect(()=>{

fetchClients();
fetchProjects();

},[]);


// ================= HANDLE INPUT =================
const handleChange = (e)=>{

const {name,value} = e.target;

if(name==="phone"){

const numeric = value.replace(/\D/g,"");

if(numeric.length<=10){

setFormData({...formData,phone:numeric});

}

return;

}

setFormData({...formData,[name]:value});

};


// ================= SAVE CLIENT =================
const handleSubmit = async ()=>{

if(!formData.name){
alert("Enter client name");
return;
}

if(formData.phone.length!==10){
alert("Phone must be 10 digits");
return;
}

if(!formData.project){
alert("Select project");
return;
}

if(!formData.floor){
alert("Select floor");
return;
}

if(editId){

await fetch(`http://localhost:5000/api/clients/${editId}`,{

method:"PUT",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(formData)

});

}else{

await fetch("http://localhost:5000/api/clients",{

method:"POST",
headers:{"Content-Type":"application/json"},
body:JSON.stringify(formData)

});

}

fetchClients();

setShowForm(false);
setEditId(null);

setFormData({

name:"",
phone:"",
address:"",
project:"",
floor:"",
room:"",
amount_paid:""

});

};


// ================= DELETE CLIENT =================
const handleDelete = async(id)=>{

await fetch(`http://localhost:5000/api/clients/${id}`,{
method:"DELETE"
});

fetchClients();

};


// ================= EDIT CLIENT =================
const handleEdit = (client)=>{

setFormData({

name:client.name,
phone:client.phone,
address:client.address,
project:client.project,
floor:client.floor,
room:client.room,
amount_paid:client.amount_paid

});

setEditId(client.id);
setShowForm(true);

};


// ================= SEARCH =================
const filteredClients = clients.filter(c=>

c.name.toLowerCase().includes(search.toLowerCase()) ||
c.project.toLowerCase().includes(search.toLowerCase())

);


// ================= GET FLOORS =================
const selectedProject = projects.find(
p => p.name === formData.project
);

const floors = selectedProject
? Array.from({length:selectedProject.floors},(_,i)=>i+1)
: [];


return(

<div className="flex bg-gray-100 min-h-screen">

<Sidebar/>

<div className="flex-1 flex flex-col">

<Topbar/>

<div className="p-8">


<div className="flex justify-between mb-6">

<h1 className="text-3xl font-semibold">
Client & Booking Details
</h1>

<button
onClick={()=>setShowForm(true)}
className="bg-orange-500 text-white px-6 py-3 rounded-xl"
>
+ Add Client
</button>

</div>


<input
type="text"
placeholder="Search by name or project..."
value={search}
onChange={(e)=>setSearch(e.target.value)}
className="border px-4 py-3 rounded-xl w-full mb-6"
/>


{showForm && (

<div className="bg-white p-8 rounded-2xl shadow mb-8">

<div className="grid grid-cols-2 gap-6">


<input
name="name"
placeholder="Name"
value={formData.name}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
/>


<input
name="phone"
placeholder="Phone"
value={formData.phone}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
/>


<input
name="address"
placeholder="Address"
value={formData.address}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
/>

<select
name="project"
value={formData.project}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
>

<option value="">
-- Select Project --
</option>

{projects.map((p)=>(
<option key={p.id} value={p.name}>
{p.name}
</option>
))}

</select>



<select
name="floor"
value={formData.floor}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
>

<option value="">
-- Select Floor --
</option>

{floors.map(f=>(

<option key={f} value={f}>
Floor {f}
</option>

))}

</select>


<select
name="room"
value={formData.room}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
>

<option value="">
-- Select Room --
</option>

{generateRooms(formData.floor).map(room=>(

<option key={room} value={room}>
{room}
</option>

))}

</select>


<input
type="number"
name="amount_paid"
placeholder="Amount Paid"
value={formData.amount_paid}
onChange={handleChange}
className="border px-4 py-3 rounded-xl"
/>

</div>


<div className="mt-6 flex gap-4">

<button
onClick={handleSubmit}
className="bg-orange-500 text-white px-6 py-3 rounded-xl"
>
Save
</button>

<button
onClick={()=>setShowForm(false)}
className="bg-gray-300 px-6 py-3 rounded-xl"
>
Cancel
</button>

</div>

</div>

)}


<div className="bg-white p-6 rounded-2xl shadow">

<table className="w-full">

<thead>

<tr className="border-b text-left">

<th>Name</th>
<th>Phone</th>
<th>Address</th>
<th>Project</th>
<th>Floor</th>
<th>Room</th>
<th>Paid</th>
<th>Actions</th>

</tr>

</thead>

<tbody>

{filteredClients.map(c=>(

<tr key={c.id} className="border-b">

<td>{c.name}</td>
<td>{c.phone}</td>
<td>{c.address}</td>
<td>{c.project}</td>
<td>{c.floor}</td>
<td>{c.room}</td>
<td>₹{c.amount_paid}</td>

<td className="space-x-3">

<button
onClick={()=>handleEdit(c)}
className="text-blue-600"
>
Edit
</button>

<button
onClick={()=>handleDelete(c.id)}
className="text-red-600"
>
Delete
</button>

</td>

</tr>

))}

</tbody>

</table>

</div>

</div>

</div>

</div>

);

}
